from math import pi

class Circle:
    def __init__(self, radius):
        self.__radius = radius

    def getradius(self):
        return self.__radius

    def getarea(self):
        return pi * (self.getradius() ** 2)

class Cylinder(Circle):
    def __init__(self, radius, height):
        super().__init__(radius)
        self.__height = height

    def getarea(self):
        return 2 * super().getarea() + self.getradius() * pi * 2 * self.__height

    def getvolume(self):
        return super().getarea() * self.__height

    def __str__(self):
        return (
            f"BasalArea:{super().getarea():.03f}\n"
            f"SupfaceArea:{self.getarea():.03f}\n"
            f"Volume:{self.getvolume():.03f}"
        )

r, h = map(float, input().split())
cy = Cylinder(r, h)
print(cy)
